class ExpressionVisitor(ast.NodeVisitor):
    def visit(self, node):
        allowed_nodes = [ast.Expr, ast.Num, ast.BinOp]
        if type(node) not in allowed_nodes:
            raise ValueError(f"Invalid expression: {type(node).__name__}")
        return super().visit(node)

