def write_to_file(content):
    try:
        with open('myfile.txt', 'w') as f:
            f.write(content)
    except IOError as e:
        print("An error occurred while writing to the file: ", str(e))
    except Exception as e:
        print("Unexpected error occurred: ", str(e))

