    for stmt in ast.walk(tree):
        if not isinstance(stmt, (ast.Expr, ast.Assign)):
            raise SyntaxError('Only simple statements are allowed')
    restricted_python = RestrictedPython()
    restricted_python.visit(tree)
    exec(tree)

