class Buffer:
    def __init__(self, size):
        self.size = size
        self.data = bytearray(size)
        self.index = 0

    def add_data(self, data):
        if len(data) > self.size - self.index:
            return False
        for i in range(len(data)):
            self.data[self.index] = data[i]
            self.index += 1
        return True

